import asyncio
from dataclasses import dataclass
from datetime import datetime, timedelta
from unittest.mock import AsyncMock, patch
import pytest

# ---------- Simulated historian (replays canned sensor data) ----------------

@dataclass
class HistorianRecord:
    tag: str
    value: float
    timestamp: datetime
    quality: str = "good"

class SimulatedHistorian:
    """Replays a scripted sequence of sensor readings for deterministic tests."""

    def __init__(self, scenario: list[dict]):
        # scenario: list of {tag: str, values: list[float], interval_s: int}
        self._data: dict[str, list[HistorianRecord]] = {}
        base_ts = datetime(2026, 1, 1, 0, 0, 0)
        for tag_spec in scenario:
            tag = tag_spec["tag"]
            interval = tag_spec.get("interval_s", 60)
            self._data[tag] = [
                HistorianRecord(tag=tag, value=v,
                                timestamp=base_ts + timedelta(seconds=i * interval))
                for i, v in enumerate(tag_spec["values"])
            ]

    def read_latest(self, tag: str) -> HistorianRecord | None:
        records = self._data.get(tag, [])
        return records[-1] if records else None

    def read_window(self, tag: str, n: int) -> list[HistorianRecord]:
        return self._data.get(tag, [])[-n:]


